const b = $input.first().json.body ?? $input.first().json;
return [{
  json: {
    title: String(b.title ?? b.subject ?? 'Urgent'),
    link: String(b.url ?? b.source_url ?? 'manual://webhook'),
    contentSnippet: String(b.text ?? b.summary ?? b.description ?? ''),
  },
}];

const item = $input.first().json;
const schema = [
  '{',
  '  "event_type": "changement_norme|nouvelle_obligation|sanction|subvention",',
  '  "instruments_impactes": ["liste ISIN ou symbols"],',
  '  "direction": "positif|négatif|neutre",',
  '  "impact_estime_pct": number,',
  '  "raison": "phrase courte",',
  '  "niveau_urgence": "low|medium|high"',
  '}',
].join('\n');

const prompt = [
  'Tu es un analyste quantitatif spécialisé en arbitrage réglementaire.',
  'Extraire au format JSON uniquement :',
  schema,
  '',
  'Titre : ' + (item.title || ''),
  'Lien : ' + (item.link || ''),
  'Extrait : ' + (item.contentSnippet || ''),
].join('\n');

return [{
  json: {
    link: item.link,
    title: item.title,
    contentSnippet: item.contentSnippet || '',
    openai_body: {
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: 'Réponds uniquement avec un objet JSON valide, sans markdown.' },
        { role: 'user', content: prompt },
      ],
      response_format: { type: 'json_object' },
      temperature: 0.15,
    },
  },
}];

const res = $input.first().json;
const txt = res.choices?.[0]?.message?.content || '{}';
let extracted = {};
try { extracted = JSON.parse(txt); } catch { extracted = { parse_error: true, raw: String(txt).slice(0, 2000) }; }

const prev = $('Build arbitrage LLM payload').first().json;
const crypto = require('crypto');
const hash = crypto.createHash('sha256').update(`${prev.title}|${prev.link}|${txt}`).digest('hex');
const impact = Number(extracted.impact_estime_pct || 0);
const impactScore = Math.min(100, Math.abs(impact) * 1.1);

const escSql = (s) => String(s ?? '').replace(/'/g, "''");
const tag = 'rg' + crypto.randomBytes(6).toString('hex');
const ej = JSON.stringify(extracted);

const query = `INSERT INTO fl_regulatory_events (source_url, content_hash, title, extracted_json, event_date, impact_score) VALUES (
  '${escSql(prev.link)}',
  '${escSql(hash)}',
  '${escSql(prev.title)}',
  $${tag}$${ej}$${tag}$::jsonb,
  now(),
  ${Number(impactScore.toFixed(4))}
) ON CONFLICT (source_url, content_hash) DO UPDATE SET
  title = EXCLUDED.title,
  extracted_json = EXCLUDED.extracted_json,
  event_date = EXCLUDED.event_date,
  impact_score = EXCLUDED.impact_score
RETURNING id`;

return [{ json: { query, extracted, link: prev.link, title: prev.title } }];

const eventRow = $('PG insert regulatory event').first().json;
const eventId = eventRow.id;
if (!eventId) {
  return [{ json: { skip: true, reason: 'no_event_id', confidence: 0 } }];
}

const extracted = $('Parse OpenAI + SQL regulatory').first().json.extracted || {};

const niveau = String(extracted.niveau_urgence || '').toLowerCase();
let base = 45;
if (niveau === 'high') base = 72;
else if (niveau === 'medium') base = 55;
else if (niveau === 'low') base = 38;

const impact = Number(extracted.impact_estime_pct || 0);
let confidence = base + Math.min(28, Math.abs(impact) * 1.6);
confidence = Math.max(0, Math.min(100, confidence));

const dir = String(extracted.direction || '').toLowerCase();
let signal = 'HOLD';
if (dir.includes('positif')) signal = 'BUY';
else if (dir.includes('négatif') || dir.includes('negatif')) signal = 'SELL';

const tokens = (extracted.instruments_impactes || []).map((t) => String(t).trim()).filter(Boolean);
const rows = $input.all().map((i) => i.json).filter((r) => r && r.isin);

const out = [];
for (const tok of tokens) {
  const u = tok.toUpperCase();
  let inst = rows.find((r) => String(r.isin).toUpperCase() === u);
  if (!inst) inst = rows.find((r) => String(r.symbol || '').toUpperCase() === u);
  if (!inst) continue;

  const esc = (s) => String(s).replace(/'/g, "''");
  const query = `INSERT INTO fl_arbitrage_matches (event_id, instrument_id, signal, confidence, expected_return) VALUES (
  ${Number(eventId)},
  '${esc(String(inst.isin))}',
  '${signal}',
  ${Number(confidence.toFixed(2))},
  ${Number(impact)}
) ON CONFLICT (event_id, instrument_id) DO UPDATE SET
  signal = EXCLUDED.signal,
  confidence = EXCLUDED.confidence,
  expected_return = EXCLUDED.expected_return
RETURNING id`;

  out.push({
    json: {
      skip: false,
      query,
      confidence,
      signal,
      isin: inst.isin,
      symbol: inst.symbol,
      extracted,
    },
  });
}

if (!out.length) {
  return [{ json: { skip: true, reason: 'no_instrument_match', confidence: 0 } }];
}
return out;

